<?php $title='Diagnostics';require __DIR__.'/partials/header.php';?><h1 class="h4 mb-3">System diagnostics</h1><div class="card mb-3"><div class="table-responsive"><table class="table table-sm mb-0"><tbody><?php foreach($report as $key=>$value):?><tr><th><?=e(ucwords(str_replace('_',' ',$key)))?></th><td><code><?=e(is_array($value)?json_encode($value,JSON_UNESCAPED_SLASHES):(string)$value)?></code></td></tr><?php endforeach?></tbody></table></div></div><?php if($streamDiagnostics):?><h2 class="h5">Active encoding profile</h2><pre class="bg-dark text-light p-3 rounded overflow-auto"><?=e(json_encode($streamDiagnostics,JSON_PRETTY_PRINT|JSON_UNESCAPED_SLASHES))?></pre><?php endif?><?php require __DIR__.'/partials/footer.php'; ?>
